function viewPastAttendanceDetails(index) {
    const history = getAttendanceHistory();
    const entry = history[index];
    if (!entry) return;

    const classVal = entry.class || 'm3';
    const roomVal = entry.room || '1';
    const roster = (studentRosters[classVal] && studentRosters[classVal][roomVal]) ? studentRosters[classVal][roomVal] : studentRosters['m3']['1'];

    const studentNames = {};
    roster.forEach(s => {
        studentNames[s.id] = { name: s.name, email: s.email, avatar: s.avatar };
    });

    let rowsHTML = '';
    Object.keys(entry.records).forEach(sid => {
        const student = studentNames[sid];
        if (!student) return;
        const status = entry.records[sid];

        let statusBadge = '';
        if (status === 'present') {
            statusBadge = '<span class="status-badge present"><i class="fa-solid fa-check-circle"></i> มาเรียน</span>';
        } else if (status === 'late') {
            statusBadge = '<span class="status-badge late"><i class="fa-solid fa-clock"></i> สาย</span>';
        } else if (status === 'leave') {
            statusBadge = '<span class="status-badge leave"><i class="fa-solid fa-envelope"></i> ลา</span>';
        } else if (status === 'absent') {
            statusBadge = '<span class="status-badge absent"><i class="fa-solid fa-xmark-circle"></i> ขาดเรียน</span>';
        }

        rowsHTML += `
            <tr style="opacity: ${status === 'absent' ? '0.6' : status === 'leave' ? '0.85' : '1'};">
                <td style="padding: 12px 16px;">
                    <div class="student-cell">
                        <div class="student-avatar" style="${sid.endsWith('2') ? 'background: #e0f2fe; color: #0284c7;' : sid.endsWith('3') ? 'background: #ffedd5; color: #ea580c;' : ''}">${student.avatar}</div>
                        <div>
                            <div style="font-weight: 500; color: var(--text-main);">${student.name}</div>
                            ${student.email ? `<div style="font-size: 0.8rem; color: var(--text-muted);">${student.email}</div>` : ''}
                        </div>
                    </div>
                </td>
                <td style="padding: 12px 16px; text-align: right;">${statusBadge}</td>
            </tr>
        `;
    });

    const classLabel = classVal === 'm1' ? 'ม.1' : classVal === 'm2' ? 'ม.2' : classVal === 'm3' ? 'ม.3' : 'ม.3';
    const roomLabel = roomVal ? `/${roomVal}` : '/1';
    const modalTitle = `<i class="fa-regular fa-calendar-check" style="color: var(--primary);"></i> ประวัติเข้าเรียนวันที่ ${entry.date} (ห้อง ${classLabel}${roomLabel})`;
    const modalBodyHTML = `
        <p style="font-size:0.9rem; color:var(--text-muted); margin-bottom:12px;">รายงานสรุปสิทธิ์ผู้เรียนประจำรายวิชา วิทยาการคำนวณ ${classLabel}${roomLabel}</p>
        <table class="data-table" style="border: 1px solid var(--border); border-radius: 8px;">
            <thead>
                <tr style="background: var(--secondary);">
                    <th style="padding: 10px 16px;">ชื่อนักเรียน</th>
                    <th style="padding: 10px 16px; text-align: right;">สถานะเช็คชื่อ</th>
                </tr>
            </thead>
            <tbody>
                ${rowsHTML}
            </tbody>
        </table>
    `;

    openReportModal(modalTitle, modalBodyHTML);
}

